<template><section class="page"><header><div><h2>{{t('promptops.datasets.title')}}</h2><p>{{t('promptops.datasets.description')}}</p></div><div class="actions"><button @click="showImport=true">{{t('promptops.datasets.importDataset')}}</button><button class="primary" @click="showEditor=true">{{t('promptops.datasets.create')}}</button></div></header><div class="stats"><article><b>{{total}}</b><span>{{t('promptops.datasets.title')}}</span></article><article><b>{{activeCount}}</b><span>{{t('promptops.datasets.active')}}</span></article><article><b>{{archivedCount}}</b><span>{{t('promptops.datasets.archived')}}</span></article><article><b>{{totalCases}}</b><span>{{t('promptops.datasets.testCases')}}</span></article></div><div class="filters"><input v-model="store.search" :placeholder="t('promptops.datasets.search')"><select v-model="store.status"><option value="">{{t('promptops.datasets.allStatuses')}}</option><option value="active">{{t('promptops.datasets.active')}}</option><option value="archived">{{t('promptops.datasets.archived')}}</option></select><select v-model="store.sortBy"><option value="updatedAt">{{t('promptops.datasets.updated')}}</option><option value="createdAt">{{t('promptops.datasets.created')}}</option><option value="name">{{t('promptops.datasets.name')}}</option></select><button @click="store.clear()">{{t('promptops.datasets.clearFilters')}}</button></div><p v-if="loading">{{t('promptops.common.loading')}}</p><p v-else-if="error" class="error">{{error}} <button @click="load">{{t('promptops.common.retry')}}</button></p><div v-else-if="!items.length" class="empty">{{store.search||store.status?t('promptops.datasets.noResults'):t('promptops.datasets.empty')}}</div><table v-else><thead><tr><th>{{t('promptops.datasets.name')}}</th><th>{{t('promptops.datasets.status')}}</th><th>{{t('promptops.datasets.testCases')}}</th><th>{{t('promptops.datasets.created')}}</th><th>{{t('promptops.datasets.updated')}}</th><th>{{t('promptops.datasets.actions')}}</th></tr></thead><tbody><tr v-for="item in items" :key="item.id"><td><b>{{item.name}}</b><small>{{item.description}}</small></td><td><span class="status">{{t(`promptops.datasets.${item.status}`)}}</span></td><td>{{counts[item.id]??0}}</td><td>{{date(item.createdAt)}}</td><td>{{date(item.updatedAt)}}</td><td><RouterLink :to="`/datasets/${item.id}`">{{t('promptops.datasets.view')}}</RouterLink><button @click="editing=item">{{t('promptops.datasets.metadata')}}</button><button @click="duplicate(item)">{{t('promptops.datasets.duplicate')}}</button><button v-if="item.status==='active'" @click="archive(item)">{{t('promptops.datasets.archive')}}</button><button v-else @click="restore(item)">{{t('promptops.datasets.restore')}}</button><button @click="exportItem(item)">{{t('promptops.datasets.exportDataset')}}</button></td></tr></tbody></table><div class="pager"><button :disabled="store.page<=1" @click="store.page--">‹</button><span>{{store.page}}</span><button :disabled="items.length<pageSize" @click="store.page++">›</button></div><DatasetEditor v-if="showEditor||editing" :dataset="editing" :saving="saving" @close="closeEditor" @save="saveDataset"/><DatasetImportDialog v-if="showImport" @close="showImport=false" @imported="imported"/></section></template>
<script setup lang="ts">import{computed,onMounted,ref,watch}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import{useI18n}from'vue-i18n';import type{Dataset}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import{usePromptOpsUiStore}from'../../stores/promptops/usePromptOpsUiStore';import{useDatasetUiStore}from'../../stores/promptops/useDatasetUiStore';import DatasetEditor from'../../components/promptops/datasets/DatasetEditor.vue';import DatasetImportDialog from'../../components/promptops/datasets/DatasetImportDialog.vue';const{t}=useI18n(),services=usePromptOpsServices(),workspace=usePromptOpsUiStore(),store=useDatasetUiStore(),route=useRoute(),router=useRouter();const items=ref<Dataset[]>([]),counts=ref<Record<string,number>>({}),loading=ref(false),error=ref(''),showEditor=ref(false),showImport=ref(false),editing=ref<Dataset>(),saving=ref(false),total=ref(0),activeCount=ref(0),archivedCount=ref(0),totalCases=ref(0),pageSize=10;const load=async()=>{loading.value=true;error.value='';try{const result=await services.datasetQueryService.list({workspaceId:workspace.currentWorkspaceId,search:store.search,status:store.status||undefined,sortBy:store.sortBy,sortDirection:store.sortDirection,limit:pageSize,offset:(store.page-1)*pageSize});items.value=result.items;counts.value=result.testCaseCounts;total.value=result.total;const[a,b,all]=await Promise.all([services.datasetQueryService.list({workspaceId:workspace.currentWorkspaceId,status:'active',limit:100}),services.datasetQueryService.list({workspaceId:workspace.currentWorkspaceId,status:'archived',limit:100}),services.datasetQueryService.list({workspaceId:workspace.currentWorkspaceId,limit:100})]);activeCount.value=a.total;archivedCount.value=b.total;totalCases.value=Object.values(all.testCaseCounts).reduce((x,y)=>x+y,0)}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{loading.value=false}};watch([()=>store.search,()=>store.status,()=>store.sortBy,()=>store.sortDirection,()=>store.page],load);onMounted(()=>{if(route.name==='promptops-dataset-new')showEditor.value=true;void load()});const closeEditor=()=>{showEditor.value=false;editing.value=undefined;if(route.name==='promptops-dataset-new')void router.replace('/datasets')};const saveDataset=async(value:{name:string;description:string})=>{saving.value=true;try{const saved=editing.value?await services.datasetService.update(editing.value.id,value):await services.datasetService.create({workspaceId:workspace.currentWorkspaceId,...value});closeEditor();await load();if(!editing.value)await router.push(`/datasets/${saved.id}`)}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{saving.value=false}};const duplicate=async(item:Dataset)=>{await services.datasetService.duplicate(item.id);await load()};const archive=async(item:Dataset)=>{if(confirm(String(t('promptops.datasets.archiveConfirm')))){await services.datasetService.archive(item.id);await load()}};const restore=async(item:Dataset)=>{await services.datasetService.restore(item.id);await load()};const download=(name:string,value:unknown)=>{const blob=new Blob([JSON.stringify(value,null,2)],{type:'application/json;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`${name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')||'dataset'}-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(url)};const exportItem=async(item:Dataset)=>download(item.name,await services.datasetService.exportDocument(item.id));const imported=(id:string)=>{showImport.value=false;void router.push(`/datasets/${id}`)};const date=(value:string)=>new Date(value).toLocaleDateString()</script>
<style scoped>.page{display:grid;gap:18px}header,.actions,.filters,.pager{display:flex;gap:10px;align-items:center}header{justify-content:space-between}h2{margin:0}.primary{background:#2563eb;color:#fff}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.stats article{padding:16px;background:var(--n-color,#fff);border:1px solid #e5e7eb;border-radius:9px;display:grid}.stats b{font-size:24px}.filters input{flex:1}input,select,button{padding:9px;border:1px solid #cbd5e1;border-radius:7px;background:var(--n-color,#fff);color:inherit}table{width:100%;border-collapse:collapse;background:var(--n-color,#fff)}th,td{text-align:left;padding:11px;border-bottom:1px solid #e5e7eb}td button,td a{margin:2px 5px}.status{padding:3px 7px;border-radius:10px;background:#e0e7ff}.empty{text-align:center;padding:50px}.error{color:#b91c1c}.pager{justify-content:center}small{display:block;color:#64748b}@media(max-width:900px){.stats{grid-template-columns:1fr 1fr}.filters{flex-wrap:wrap}}</style>
